//! MolmoAct2 action expert — pi0-style flow-matching DiT denoiser.
//!
//! A separate 768-dim bidirectional transformer with ONE block per LM layer
//! (36). Given the VLM's per-layer K/V cache (the depth-aware context), it
//! denoises a random action chunk `[horizon, action_dim]` over a fixed number
//! of forward-Euler flow-matching steps, producing the model-space action
//! velocity-integrated to t=1.
//!
//! Generation (matches HF `generate_actions_from_inputs` → `_run_action_flow_loop`):
//!   trajectory = randn(horizon, max_action_dim)
//!   for idx in 0..steps:
//!       t = idx / steps                      // 0.0, 0.1, ..., 0.9
//!       v = forward(trajectory, t, vlm_kv)   // velocity field
//!       trajectory += (1/steps) * v          // forward Euler
//!   return trajectory                        // model space; caller q01_q99-unnormalizes
//!
//! Each DiT block (AdaLN-Zero, 9-way modulation from the timestep):
//!   x += gate_msa * self_attn(modulate(self_norm(x), shift_msa, scale_msa))
//!   x += gate_mca * cross_attn(modulate(cross_norm(x), shift_mca, scale_mca), vlm_kv)
//!   x += gate_mlp * mlp(modulate(ff_norm(x), shift_mlp, scale_mlp))
//! self_attn: qkv+bias, weightless per-head qk-norm, half-split RoPE, full attn.
//! cross_attn: q_proj+bias, weightless q-norm; K/V = context_norm(context_proj(vlm_kv)),
//!             with the block's weightless cross k-norm applied to K.
//! mlp: SwiGLU (silu(gate)*up -> down), all linears carry bias.
//! ALL RMSNorms are WEIGHTLESS (HF `elementwise_affine=False`).

use std::sync::Arc;

use crate::cat_map_route::{
    admit_cat_map_route, certified_route_returns_at_period, quantized_l2_energy,
    route_carrier_rows, route_row_prefix_f32, unroute_row_prefix_f32, CatMapRouteAdmission,
    CatMapRouteEvidence, CertifiedCatRoute,
};
use crate::loader::WeightBackend;
use crate::math::{
    accumulate_weighted, dot_product, mat_vec_f32, rope_neox, softmax, swiglu_inplace,
};
use crate::model_molmoact2_config::MolmoAct2ActionExpertConfig;

/// Pre-resolved tensor names for one action-expert block.
struct AeBlockNames {
    sa_qkv_w: String,
    sa_qkv_b: String,
    sa_out_w: String,
    sa_out_b: String,
    ca_q_w: String,
    ca_q_b: String,
    ca_out_w: String,
    ca_out_b: String,
    mlp_gate_w: String,
    mlp_gate_b: String,
    mlp_up_w: String,
    mlp_up_b: String,
    mlp_down_w: String,
    mlp_down_b: String,
    mod_w: String,
    mod_b: String,
}

impl AeBlockNames {
    fn new(i: usize) -> Self {
        Self {
            sa_qkv_w: format!("ae_blk_{i}_sa_qkv_weight"),
            sa_qkv_b: format!("ae_blk_{i}_sa_qkv_bias"),
            sa_out_w: format!("ae_blk_{i}_sa_out_weight"),
            sa_out_b: format!("ae_blk_{i}_sa_out_bias"),
            ca_q_w: format!("ae_blk_{i}_ca_q_weight"),
            ca_q_b: format!("ae_blk_{i}_ca_q_bias"),
            ca_out_w: format!("ae_blk_{i}_ca_out_weight"),
            ca_out_b: format!("ae_blk_{i}_ca_out_bias"),
            mlp_gate_w: format!("ae_blk_{i}_mlp_gate_weight"),
            mlp_gate_b: format!("ae_blk_{i}_mlp_gate_bias"),
            mlp_up_w: format!("ae_blk_{i}_mlp_up_weight"),
            mlp_up_b: format!("ae_blk_{i}_mlp_up_bias"),
            mlp_down_w: format!("ae_blk_{i}_mlp_down_weight"),
            mlp_down_b: format!("ae_blk_{i}_mlp_down_bias"),
            mod_w: format!("ae_blk_{i}_mod_weight"),
            mod_b: format!("ae_blk_{i}_mod_bias"),
        }
    }
}

/// Cross-attention context for one LM layer: K and V already projected to the
/// action-expert head layout `[seq, num_heads * head_dim]`, K already k-normed.
struct LayerContext {
    k: Vec<f32>, // [seq * hidden]
    v: Vec<f32>, // [seq * hidden]
}

#[derive(Clone, Debug)]
pub struct CatMapShadowStepTelemetry {
    pub step: usize,
    pub ticks: u32,
    pub evidence: CatMapRouteEvidence,
    pub admission: CatMapRouteAdmission,
}

#[derive(Clone, Debug)]
pub struct CatMapShadowTelemetry {
    pub route: CertifiedCatRoute,
    pub carrier_rows: usize,
    pub fingerprint_verified: bool,
    pub steps: Vec<CatMapShadowStepTelemetry>,
}

impl CatMapShadowTelemetry {
    pub fn admitted_steps(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step.admission, CatMapRouteAdmission::Admitted { .. }))
            .count()
    }

    pub fn rejected_steps(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step.admission, CatMapRouteAdmission::Rejected { .. }))
            .count()
    }

    pub fn shadow_only_steps(&self) -> usize {
        self.steps
            .iter()
            .filter(|step| matches!(step.admission, CatMapRouteAdmission::ShadowOnly { .. }))
            .count()
    }
}

#[derive(Clone, Debug)]
pub struct ActionWithCatMapShadow {
    pub action: Vec<f32>,
    pub cat_map_shadow: Option<CatMapShadowTelemetry>,
}

#[derive(Clone, Debug)]
pub struct CatMapFastPathStepTelemetry {
    pub step: usize,
    pub ticks: u32,
    pub trajectory_energy: u64,
    pub delta_energy: u64,
    pub max_delta: f32,
    pub topology_depth: u8,
    pub converged: bool,
}

#[derive(Clone, Debug)]
pub struct CatMapFastPathTelemetry {
    pub route: CertifiedCatRoute,
    pub carrier_rows: usize,
    pub fingerprint_verified: bool,
    pub convergence_epsilon: f32,
    pub configured_steps: usize,
    pub steps: Vec<CatMapFastPathStepTelemetry>,
}

impl CatMapFastPathTelemetry {
    pub fn executed_steps(&self) -> usize {
        self.steps.len()
    }

    pub fn converged(&self) -> bool {
        self.steps
            .last()
            .map(|step| step.converged)
            .unwrap_or(false)
    }

    pub fn skipped_steps(&self) -> usize {
        self.configured_steps.saturating_sub(self.executed_steps())
    }
}

#[derive(Clone, Debug)]
pub struct ActionWithCatMapFastPath {
    pub action: Vec<f32>,
    pub cat_map_fast_path: CatMapFastPathTelemetry,
}

pub struct MolmoAct2ActionExpert {
    config: MolmoAct2ActionExpertConfig,
    backend: Arc<dyn WeightBackend>,
    blocks: Vec<AeBlockNames>,
}

impl MolmoAct2ActionExpert {
    pub fn new(config: MolmoAct2ActionExpertConfig, backend: Arc<dyn WeightBackend>) -> Self {
        let blocks = (0..config.num_layers).map(AeBlockNames::new).collect();
        Self {
            config,
            backend,
            blocks,
        }
    }

    /// Generate an action chunk from the VLM per-layer K/V cache.
    ///
    /// `vlm_kv`: one (k, v) pair per LM layer; each is `[seq_len * llm_kv_dim]`
    ///           (rotated K and V exactly as cached by the LM).
    /// `horizon`: number of action timesteps to produce (<= max_action_horizon).
    /// `seed`: RNG seed for the initial noise (deterministic gate reproducibility).
    ///
    /// Returns the flow-integrated action chunk `[horizon * max_action_dim]` in
    /// model space (caller slices the real action dim and q01_q99-unnormalizes).
    pub fn generate(
        &self,
        vlm_kv: &[(Vec<f32>, Vec<f32>)],
        seq_len: usize,
        horizon: usize,
        seed: u64,
    ) -> Result<Vec<f32>, String> {
        Ok(self
            .generate_internal(vlm_kv, seq_len, horizon, seed, None)?
            .action)
    }

    /// Generate the canonical action chunk while evaluating cat-map routed
    /// proposals in shadow mode. The returned `action` is still the canonical
    /// forward-Euler trajectory; telemetry records which routed proposals would
    /// have passed the formal admission gate.
    pub fn generate_with_cat_map_shadow(
        &self,
        vlm_kv: &[(Vec<f32>, Vec<f32>)],
        seq_len: usize,
        horizon: usize,
        seed: u64,
        route: CertifiedCatRoute,
    ) -> Result<ActionWithCatMapShadow, String> {
        self.generate_internal(vlm_kv, seq_len, horizon, seed, Some(route))
    }

    /// Generate an action chunk with a single-forward cat-map preconditioned
    /// flow loop. Each step runs the denoiser once in routed coordinates, then
    /// unroutes the velocity before applying the Euler update. This is allowed
    /// to change the action; use shadow mode when parity telemetry is needed.
    pub fn generate_with_cat_map_fast_path(
        &self,
        vlm_kv: &[(Vec<f32>, Vec<f32>)],
        seq_len: usize,
        horizon: usize,
        seed: u64,
        route: CertifiedCatRoute,
        convergence_epsilon: f32,
    ) -> Result<ActionWithCatMapFastPath, String> {
        let cfg = &self.config;
        if vlm_kv.len() != cfg.num_layers {
            return Err(format!(
                "action expert needs {} layers of VLM KV, got {}",
                cfg.num_layers,
                vlm_kv.len()
            ));
        }
        if horizon > cfg.max_action_horizon {
            return Err(format!(
                "horizon {horizon} exceeds max_action_horizon {}",
                cfg.max_action_horizon
            ));
        }
        if horizon < route_carrier_rows(route) {
            return Err(format!(
                "horizon {horizon} is smaller than cat-map carrier rows {}",
                route_carrier_rows(route)
            ));
        }
        if !convergence_epsilon.is_finite() || convergence_epsilon < 0.0 {
            return Err("cat-map convergence epsilon must be finite and non-negative".to_string());
        }

        let dim = cfg.max_action_dim;
        let contexts = self.build_contexts(vlm_kv, seq_len)?;
        let mut traj = vec![0.0f32; horizon * dim];
        let mut rng = SplitMix64::new(seed);
        for x in traj.iter_mut() {
            *x = rng.next_gaussian();
        }

        let steps = cfg.flow_matching_num_steps.max(1);
        let dt = 1.0 / steps as f32;
        let mut telemetry = CatMapFastPathTelemetry {
            route,
            carrier_rows: route_carrier_rows(route),
            fingerprint_verified: certified_route_returns_at_period(route),
            convergence_epsilon,
            configured_steps: steps,
            steps: Vec::with_capacity(steps),
        };

        for idx in 0..steps {
            let t = idx as f32 / steps as f32;
            let ticks = cat_map_route_ticks(route, idx);
            let routed_traj = route_row_prefix_f32(&traj, dim, route, ticks)
                .map_err(|e| format!("cat-map fast path route: {e:?}"))?;
            let routed_velocity = self.forward(&routed_traj, horizon, t, &contexts)?;
            let velocity = unroute_row_prefix_f32(&routed_velocity, dim, route, ticks)
                .map_err(|e| format!("cat-map fast path unroute: {e:?}"))?;

            let mut next = traj.clone();
            for i in 0..next.len() {
                next[i] += dt * velocity[i];
            }

            let max_delta = max_abs_delta(&traj, &next);
            let converged = convergence_epsilon > 0.0 && max_delta <= convergence_epsilon;
            telemetry.steps.push(CatMapFastPathStepTelemetry {
                step: idx,
                ticks,
                trajectory_energy: quantized_l2_energy(&next),
                delta_energy: quantized_l2_delta(&traj, &next),
                max_delta,
                topology_depth: action_topology_depth(&next, dim),
                converged,
            });
            traj = next;
            if converged {
                break;
            }
        }

        Ok(ActionWithCatMapFastPath {
            action: traj,
            cat_map_fast_path: telemetry,
        })
    }

    fn generate_internal(
        &self,
        vlm_kv: &[(Vec<f32>, Vec<f32>)],
        seq_len: usize,
        horizon: usize,
        seed: u64,
        shadow_route: Option<CertifiedCatRoute>,
    ) -> Result<ActionWithCatMapShadow, String> {
        let cfg = &self.config;
        if vlm_kv.len() != cfg.num_layers {
            return Err(format!(
                "action expert needs {} layers of VLM KV, got {}",
                cfg.num_layers,
                vlm_kv.len()
            ));
        }
        if horizon > cfg.max_action_horizon {
            return Err(format!(
                "horizon {horizon} exceeds max_action_horizon {}",
                cfg.max_action_horizon
            ));
        }
        let dim = cfg.max_action_dim;

        // 1. Project each LM layer's K/V into the action-expert cross context.
        let contexts = self.build_contexts(vlm_kv, seq_len)?;

        // 2. Initialize the noisy trajectory [horizon, dim].
        let mut traj = vec![0.0f32; horizon * dim];
        let mut rng = SplitMix64::new(seed);
        for x in traj.iter_mut() {
            *x = rng.next_gaussian();
        }

        let mut cat_map_shadow = shadow_route.map(|route| CatMapShadowTelemetry {
            route,
            carrier_rows: route_carrier_rows(route),
            fingerprint_verified: certified_route_returns_at_period(route),
            steps: Vec::new(),
        });

        // 3. Forward-Euler flow-matching loop.
        let steps = cfg.flow_matching_num_steps.max(1);
        let dt = 1.0 / steps as f32;
        for idx in 0..steps {
            let t = idx as f32 / steps as f32;
            let velocity = self.forward(&traj, horizon, t, &contexts)?;
            let mut canonical_next = traj.clone();
            for i in 0..canonical_next.len() {
                canonical_next[i] += dt * velocity[i];
            }

            if let Some(shadow) = cat_map_shadow.as_mut() {
                let ticks = cat_map_route_ticks(shadow.route, idx);
                let routed_traj = route_row_prefix_f32(&traj, dim, shadow.route, ticks)
                    .map_err(|e| format!("cat-map route shadow: {e:?}"))?;
                let routed_velocity = self.forward(&routed_traj, horizon, t, &contexts)?;
                let unrouted_velocity =
                    unroute_row_prefix_f32(&routed_velocity, dim, shadow.route, ticks)
                        .map_err(|e| format!("cat-map unroute shadow: {e:?}"))?;
                let mut routed_next = traj.clone();
                for i in 0..routed_next.len() {
                    routed_next[i] += dt * unrouted_velocity[i];
                }

                let evidence = CatMapRouteEvidence {
                    canonical_energy: quantized_l2_energy(&canonical_next),
                    routed_energy: quantized_l2_energy(&routed_next),
                    topology_before: action_topology_depth(&canonical_next, dim),
                    topology_after: action_topology_depth(&routed_next, dim),
                    fingerprint_verified: shadow.fingerprint_verified,
                };
                let admission = admit_cat_map_route(evidence);
                shadow.steps.push(CatMapShadowStepTelemetry {
                    step: idx,
                    ticks,
                    evidence,
                    admission,
                });
            }

            traj = canonical_next;
        }
        Ok(ActionWithCatMapShadow {
            action: traj,
            cat_map_shadow,
        })
    }

    /// Project the VLM K/V cache into per-block cross-attention contexts.
    fn build_contexts(
        &self,
        vlm_kv: &[(Vec<f32>, Vec<f32>)],
        seq_len: usize,
    ) -> Result<Vec<LayerContext>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let head_dim = cfg.head_dim();
        let n_heads = cfg.num_heads;
        let kv_dim = cfg.llm_kv_dim;
        let eps = cfg.qk_norm_eps;

        let ck_w = self.fetch("ae_ctx_k_weight")?;
        let cv_w = self.fetch("ae_ctx_v_weight")?;

        let mut contexts = Vec::with_capacity(cfg.num_layers);
        for (li, (k_in, v_in)) in vlm_kv.iter().enumerate() {
            if k_in.len() != seq_len * kv_dim || v_in.len() != seq_len * kv_dim {
                return Err(format!(
                    "layer {li} KV size mismatch: got k={} v={}, expected {}",
                    k_in.len(),
                    v_in.len(),
                    seq_len * kv_dim
                ));
            }
            let mut k_ctx = vec![0.0f32; seq_len * h];
            let mut v_ctx = vec![0.0f32; seq_len * h];
            for t in 0..seq_len {
                // context_{k,v}_proj: [h, kv_dim], no bias.
                mat_vec_f32(
                    &mut k_ctx[t * h..(t + 1) * h],
                    &k_in[t * kv_dim..(t + 1) * kv_dim],
                    &ck_w,
                    h,
                    kv_dim,
                );
                mat_vec_f32(
                    &mut v_ctx[t * h..(t + 1) * h],
                    &v_in[t * kv_dim..(t + 1) * kv_dim],
                    &cv_w,
                    h,
                    kv_dim,
                );
                // context_norm (weightless RMSNorm over the full hidden dim).
                rms_norm_noweight(&mut k_ctx[t * h..(t + 1) * h], eps);
                rms_norm_noweight(&mut v_ctx[t * h..(t + 1) * h], eps);
                // cross_attn k_norm (weightless RMSNorm per head) on K only.
                for hd in 0..n_heads {
                    let off = t * h + hd * head_dim;
                    rms_norm_noweight(&mut k_ctx[off..off + head_dim], eps);
                }
            }
            contexts.push(LayerContext { k: k_ctx, v: v_ctx });
        }
        Ok(contexts)
    }

    /// One velocity evaluation: action chunk + timestep -> velocity `[horizon*dim]`.
    fn forward(
        &self,
        traj: &[f32],
        horizon: usize,
        t: f32,
        contexts: &[LayerContext],
    ) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let dim = cfg.max_action_dim;

        // conditioning = time_embed(t): sinusoid -> Linear(.1) -> SiLU -> Linear(.3).
        let conditioning = self.time_embed(t)?;

        // x = action_embed(traj) + bias  -> [horizon, hidden].
        let ae_w = self.fetch("ae_action_embed_weight")?;
        let ae_b = self.fetch("ae_action_embed_bias")?;
        let mut x = vec![0.0f32; horizon * h];
        for tok in 0..horizon {
            let dst = &mut x[tok * h..(tok + 1) * h];
            mat_vec_f32(dst, &traj[tok * dim..(tok + 1) * dim], &ae_w, h, dim);
            for i in 0..h {
                dst[i] += ae_b[i];
            }
        }

        // 36 DiT blocks.
        for li in 0..cfg.num_layers {
            self.block(&mut x, horizon, &conditioning, &contexts[li], li)?;
        }

        // final_layer: linear(modulate(norm(x), shift, scale)) + bias -> [horizon, dim].
        let fmod_w = self.fetch("ae_final_mod_weight")?;
        let fmod_b = self.fetch("ae_final_mod_bias")?;
        let fl_w = self.fetch("ae_final_linear_weight")?;
        let fl_b = self.fetch("ae_final_linear_bias")?;
        let fmod = modulation(&conditioning, &fmod_w, &fmod_b, 2, h); // [2][h]
        let mut out = vec![0.0f32; horizon * dim];
        let eps = cfg.qk_norm_eps;
        for tok in 0..horizon {
            let mut row = x[tok * h..(tok + 1) * h].to_vec();
            rms_norm_noweight(&mut row, eps);
            modulate(&mut row, &fmod[0], &fmod[1]);
            let dst = &mut out[tok * dim..(tok + 1) * dim];
            mat_vec_f32(dst, &row, &fl_w, dim, h);
            for i in 0..dim {
                dst[i] += fl_b[i];
            }
        }
        Ok(out)
    }

    /// One DiT block, in place on `x` `[horizon, hidden]`.
    fn block(
        &self,
        x: &mut [f32],
        horizon: usize,
        conditioning: &[f32],
        ctx: &LayerContext,
        li: usize,
    ) -> Result<(), String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let head_dim = cfg.head_dim();
        let n_heads = cfg.num_heads;
        let eps = cfg.qk_norm_eps;
        let scale = 1.0 / (head_dim as f32).sqrt();
        let bn = &self.blocks[li];

        // 9-way modulation from the timestep conditioning.
        let mod_w = self.fetch(&bn.mod_w)?;
        let mod_b = self.fetch(&bn.mod_b)?;
        let m = modulation(conditioning, &mod_w, &mod_b, 9, h);
        let (shift_msa, scale_msa, gate_msa) = (&m[0], &m[1], &m[2]);
        let (shift_mca, scale_mca, gate_mca) = (&m[3], &m[4], &m[5]);
        let (shift_mlp, scale_mlp, gate_mlp) = (&m[6], &m[7], &m[8]);

        // ── Self-attention ────────────────────────────────────────────────
        {
            // h1 = modulate(self_norm(x), shift_msa, scale_msa)
            let mut h1 = vec![0.0f32; horizon * h];
            for tok in 0..horizon {
                let mut row = x[tok * h..(tok + 1) * h].to_vec();
                rms_norm_noweight(&mut row, eps);
                modulate(&mut row, shift_msa, scale_msa);
                h1[tok * h..(tok + 1) * h].copy_from_slice(&row);
            }
            let qkv_w = self.fetch(&bn.sa_qkv_w)?;
            let qkv_b = self.fetch(&bn.sa_qkv_b)?;
            let out_w = self.fetch(&bn.sa_out_w)?;
            let out_b = self.fetch(&bn.sa_out_b)?;

            // Project Q/K/V (qkv is [3*h, h]; rows 0..h = Q, h..2h = K, 2h..3h = V).
            let mut q = vec![0.0f32; horizon * h];
            let mut k = vec![0.0f32; horizon * h];
            let mut v = vec![0.0f32; horizon * h];
            let mut qkv = vec![0.0f32; 3 * h];
            for tok in 0..horizon {
                let inp = &h1[tok * h..(tok + 1) * h];
                mat_vec_f32(&mut qkv, inp, &qkv_w, 3 * h, h);
                for i in 0..3 * h {
                    qkv[i] += qkv_b[i];
                }
                q[tok * h..(tok + 1) * h].copy_from_slice(&qkv[0..h]);
                k[tok * h..(tok + 1) * h].copy_from_slice(&qkv[h..2 * h]);
                v[tok * h..(tok + 1) * h].copy_from_slice(&qkv[2 * h..3 * h]);
                // Weightless per-head qk-norm on Q and K, then half-split RoPE.
                for hd in 0..n_heads {
                    let off = tok * h + hd * head_dim;
                    rms_norm_noweight(&mut q[off..off + head_dim], eps);
                    rms_norm_noweight(&mut k[off..off + head_dim], eps);
                }
                rope_neox(
                    &mut q[tok * h..(tok + 1) * h],
                    &mut k[tok * h..(tok + 1) * h],
                    tok,
                    n_heads,
                    n_heads,
                    head_dim,
                    cfg.rope_theta,
                );
            }

            // Full (bidirectional) attention.
            let attn = self.full_attention(&q, &k, &v, horizon, horizon, n_heads, head_dim, scale);

            // O-projection + bias, gated residual add.
            let mut o = vec![0.0f32; h];
            for tok in 0..horizon {
                mat_vec_f32(&mut o, &attn[tok * h..(tok + 1) * h], &out_w, h, h);
                for i in 0..h {
                    x[tok * h + i] += gate_msa[i] * (o[i] + out_b[i]);
                }
            }
        }

        // ── Cross-attention into the VLM layer KV ─────────────────────────
        let kv_seq = ctx.v.len() / h;
        {
            let mut h2 = vec![0.0f32; horizon * h];
            for tok in 0..horizon {
                let mut row = x[tok * h..(tok + 1) * h].to_vec();
                rms_norm_noweight(&mut row, eps);
                modulate(&mut row, shift_mca, scale_mca);
                h2[tok * h..(tok + 1) * h].copy_from_slice(&row);
            }
            let q_w = self.fetch(&bn.ca_q_w)?;
            let q_b = self.fetch(&bn.ca_q_b)?;
            let out_w = self.fetch(&bn.ca_out_w)?;
            let out_b = self.fetch(&bn.ca_out_b)?;

            let mut q = vec![0.0f32; horizon * h];
            for tok in 0..horizon {
                let dst = &mut q[tok * h..(tok + 1) * h];
                mat_vec_f32(dst, &h2[tok * h..(tok + 1) * h], &q_w, h, h);
                for i in 0..h {
                    dst[i] += q_b[i];
                }
                // Weightless per-head q-norm (no RoPE on cross-attention).
                for hd in 0..n_heads {
                    let off = tok * h + hd * head_dim;
                    rms_norm_noweight(&mut q[off..off + head_dim], eps);
                }
            }

            let attn = self.full_attention(
                &q, &ctx.k, &ctx.v, horizon, kv_seq, n_heads, head_dim, scale,
            );

            let mut o = vec![0.0f32; h];
            for tok in 0..horizon {
                mat_vec_f32(&mut o, &attn[tok * h..(tok + 1) * h], &out_w, h, h);
                for i in 0..h {
                    x[tok * h + i] += gate_mca[i] * (o[i] + out_b[i]);
                }
            }
        }

        // ── SwiGLU MLP ────────────────────────────────────────────────────
        {
            let inter = cfg.intermediate_size();
            let gate_w = self.fetch(&bn.mlp_gate_w)?;
            let gate_b = self.fetch(&bn.mlp_gate_b)?;
            let up_w = self.fetch(&bn.mlp_up_w)?;
            let up_b = self.fetch(&bn.mlp_up_b)?;
            let down_w = self.fetch(&bn.mlp_down_w)?;
            let down_b = self.fetch(&bn.mlp_down_b)?;

            let mut gate = vec![0.0f32; inter];
            let mut up = vec![0.0f32; inter];
            let mut down = vec![0.0f32; h];
            for tok in 0..horizon {
                let mut row = x[tok * h..(tok + 1) * h].to_vec();
                rms_norm_noweight(&mut row, eps);
                modulate(&mut row, shift_mlp, scale_mlp);

                mat_vec_f32(&mut gate, &row, &gate_w, inter, h);
                for i in 0..inter {
                    gate[i] += gate_b[i];
                }
                mat_vec_f32(&mut up, &row, &up_w, inter, h);
                for i in 0..inter {
                    up[i] += up_b[i];
                }
                swiglu_inplace(&mut gate, &up); // gate = silu(gate) * up
                mat_vec_f32(&mut down, &gate, &down_w, h, inter);
                for i in 0..h {
                    x[tok * h + i] += gate_mlp[i] * (down[i] + down_b[i]);
                }
            }
        }

        Ok(())
    }

    /// Standard scaled-dot-product attention (full, bidirectional).
    /// q: [q_len*hidden], k/v: [kv_len*hidden] in head-major-per-token layout.
    #[allow(clippy::too_many_arguments)]
    fn full_attention(
        &self,
        q: &[f32],
        k: &[f32],
        v: &[f32],
        q_len: usize,
        kv_len: usize,
        n_heads: usize,
        head_dim: usize,
        scale: f32,
    ) -> Vec<f32> {
        let h = n_heads * head_dim;
        let mut out = vec![0.0f32; q_len * h];
        let mut scores = vec![0.0f32; kv_len];
        for t_out in 0..q_len {
            for head in 0..n_heads {
                let q_off = t_out * h + head * head_dim;
                let q_head = &q[q_off..q_off + head_dim];
                for t_src in 0..kv_len {
                    let k_off = t_src * h + head * head_dim;
                    scores[t_src] = dot_product(q_head, &k[k_off..k_off + head_dim]) * scale;
                }
                softmax(&mut scores[..kv_len]);
                let out_off = t_out * h + head * head_dim;
                let head_out = &mut out[out_off..out_off + head_dim];
                for t_src in 0..kv_len {
                    let v_off = t_src * h + head * head_dim;
                    accumulate_weighted(head_out, &v[v_off..v_off + head_dim], scores[t_src]);
                }
            }
        }
        out
    }

    /// time_embed(t) = Linear.3(SiLU(Linear.1(SinusoidalTimeEmbedding(t)))).
    fn time_embed(&self, t: f32) -> Result<Vec<f32>, String> {
        let cfg = &self.config;
        let h = cfg.hidden_size;
        let td = cfg.timestep_embed_dim;

        // Sinusoidal embedding [timestep_embed_dim].
        let half = td / 2;
        let mut emb = vec![0.0f32; td];
        let scale = -(10000f32.ln()) / (half.max(2) - 1) as f32;
        for j in 0..half {
            let freq = (j as f32 * scale).exp();
            let arg = t * freq;
            emb[j] = arg.sin();
            emb[half + j] = arg.cos();
        }

        // Linear.1: [h, td] + bias.
        let w1 = self.fetch("ae_time1_weight")?;
        let b1 = self.fetch("ae_time1_bias")?;
        let mut hid = vec![0.0f32; h];
        mat_vec_f32(&mut hid, &emb, &w1, h, td);
        for i in 0..h {
            hid[i] += b1[i];
            // SiLU
            hid[i] = hid[i] / (1.0 + (-hid[i]).exp());
        }

        // Linear.3: [h, h] + bias.
        let w3 = self.fetch("ae_time3_weight")?;
        let b3 = self.fetch("ae_time3_bias")?;
        let mut out = vec![0.0f32; h];
        mat_vec_f32(&mut out, &hid, &w3, h, h);
        for i in 0..h {
            out[i] += b3[i];
        }
        Ok(out)
    }

    fn fetch(&self, name: &str) -> Result<Vec<f32>, String> {
        let bytes = self
            .backend
            .fetch_tensor(name)
            .map_err(|e| format!("action expert tensor {name}: {e}"))?;
        if bytes.len() % 4 != 0 {
            return Err(format!("action expert tensor {name}: non-f32 byte length"));
        }
        Ok(bytes
            .chunks_exact(4)
            .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
            .collect())
    }
}

fn cat_map_route_ticks(route: CertifiedCatRoute, step: usize) -> u32 {
    let period = route.period();
    if period <= 1 {
        0
    } else {
        (step as u32 % (period - 1)) + 1
    }
}

fn max_abs_delta(before: &[f32], after: &[f32]) -> f32 {
    if before.len() != after.len() {
        return f32::INFINITY;
    }
    let mut max_delta = 0.0f32;
    for i in 0..before.len() {
        let delta = (after[i] - before[i]).abs();
        if delta > max_delta {
            max_delta = delta;
        }
    }
    max_delta
}

fn quantized_l2_delta(before: &[f32], after: &[f32]) -> u64 {
    if before.len() != after.len() {
        return u64::MAX;
    }
    let mut sum = 0.0f64;
    for i in 0..before.len() {
        let delta = after[i] - before[i];
        if delta.is_finite() {
            let v = delta as f64;
            sum += v * v;
        } else {
            return u64::MAX;
        }
    }
    if !sum.is_finite() || sum >= (u64::MAX as f64 / 1_000_000.0) {
        u64::MAX
    } else {
        (sum * 1_000_000.0).round() as u64
    }
}

fn action_topology_depth(values: &[f32], row_width: usize) -> u8 {
    if row_width == 0 || values.is_empty() || !values.len().is_multiple_of(row_width) {
        return 0;
    }
    if values.iter().any(|value| !value.is_finite()) {
        return 0;
    }

    let rows = values.len() / row_width;
    let mut active_rows = 0usize;
    let mut norms = Vec::with_capacity(rows);
    for row in 0..rows {
        let mut energy = 0.0f64;
        for &value in &values[row * row_width..(row + 1) * row_width] {
            let v = value as f64;
            energy += v * v;
        }
        let norm = energy.sqrt() as f32;
        if norm > 1.0e-6 {
            active_rows += 1;
        }
        norms.push(norm);
    }

    let active_score = ((active_rows * 4 + rows / 2) / rows).min(4) as u8;
    let mean = norms.iter().sum::<f32>() / rows as f32;
    let variance = norms
        .iter()
        .map(|norm| {
            let d = *norm - mean;
            d * d
        })
        .sum::<f32>()
        / rows as f32;
    let spread = variance.sqrt();
    let variation_score = if spread > 1.0e-1 {
        3
    } else if spread > 1.0e-2 {
        2
    } else if spread > 1.0e-4 {
        1
    } else {
        0
    };
    active_score + variation_score
}

/// AdaLN modulation: Linear(SiLU(conditioning)) -> num_chunks slices of [hidden].
fn modulation(
    conditioning: &[f32],
    w: &[f32],
    b: &[f32],
    num_chunks: usize,
    h: usize,
) -> Vec<Vec<f32>> {
    // act = SiLU(conditioning)
    let act: Vec<f32> = conditioning
        .iter()
        .map(|&x| x / (1.0 + (-x).exp()))
        .collect();
    // linear: [num_chunks*h, h] + bias.
    let mut raw = vec![0.0f32; num_chunks * h];
    mat_vec_f32(&mut raw, &act, w, num_chunks * h, h);
    for i in 0..num_chunks * h {
        raw[i] += b[i];
    }
    (0..num_chunks)
        .map(|c| raw[c * h..(c + 1) * h].to_vec())
        .collect()
}

/// DiT modulate: x = x * (1 + scale) + shift, element-wise.
fn modulate(x: &mut [f32], shift: &[f32], scale: &[f32]) {
    for i in 0..x.len() {
        x[i] = x[i] * (1.0 + scale[i]) + shift[i];
    }
}

/// Weightless RMSNorm (HF `elementwise_affine=False`): x / sqrt(mean(x^2) + eps).
/// Variance accumulated in f64 to match the reference fp32-upcast normalization.
fn rms_norm_noweight(x: &mut [f32], eps: f32) {
    let n = x.len();
    let mut sum_sq = 0.0f64;
    for &v in x.iter() {
        sum_sq += (v as f64) * (v as f64);
    }
    let inv = 1.0f64 / ((sum_sq / n as f64) + eps as f64).sqrt();
    for v in x.iter_mut() {
        *v = (*v as f64 * inv) as f32;
    }
}

/// Deterministic Gaussian sampler (SplitMix64 + Box–Muller) so action-expert
/// gating is reproducible from a seed.
struct SplitMix64 {
    state: u64,
    spare: Option<f32>,
}

impl SplitMix64 {
    fn new(seed: u64) -> Self {
        Self {
            state: seed,
            spare: None,
        }
    }

    fn next_u64(&mut self) -> u64 {
        self.state = self.state.wrapping_add(0x9E37_79B9_7F4A_7C15);
        let mut z = self.state;
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^ (z >> 31)
    }

    fn next_f32_unit(&mut self) -> f32 {
        // (0, 1) uniform.
        ((self.next_u64() >> 40) as f32 + 0.5) / (1u64 << 24) as f32
    }

    fn next_gaussian(&mut self) -> f32 {
        if let Some(s) = self.spare.take() {
            return s;
        }
        let u1 = self.next_f32_unit().max(1e-7);
        let u2 = self.next_f32_unit();
        let mag = (-2.0 * u1.ln()).sqrt();
        let z0 = mag * (std::f32::consts::TAU * u2).cos();
        let z1 = mag * (std::f32::consts::TAU * u2).sin();
        self.spare = Some(z1);
        z0
    }
}
